"use client";

import Link from "next/link";
import { useEffect, useState } from "react";

import type { AuthUser } from "../../auth/api/auth";
import { APP_EVENTS, STORAGE_KEYS } from "../../../lib/constants/api";

function readStoredUser() {
  if (typeof window === "undefined") {
    return null;
  }

  const raw = window.localStorage.getItem(STORAGE_KEYS.currentUser);
  if (!raw) {
    return null;
  }

  try {
    return JSON.parse(raw) as AuthUser;
  } catch {
    return null;
  }
}

function readSession() {
  if (typeof window === "undefined") {
    return { token: null, user: null as AuthUser | null };
  }

  return {
    token: window.localStorage.getItem(STORAGE_KEYS.accessToken),
    user: readStoredUser(),
  };
}

export function PlatformSessionStatus() {
  const [token, setToken] = useState<string | null>(null);
  const [user, setUser] = useState<AuthUser | null>(null);

  useEffect(() => {
    const syncSession = () => {
      const nextSession = readSession();
      setToken(nextSession.token);
      setUser(nextSession.user);
    };

    syncSession();
    window.addEventListener("storage", syncSession);
    window.addEventListener(APP_EVENTS.sessionChanged, syncSession);

    return () => {
      window.removeEventListener("storage", syncSession);
      window.removeEventListener(APP_EVENTS.sessionChanged, syncSession);
    };
  }, []);

  const handleDisconnect = () => {
    window.localStorage.removeItem(STORAGE_KEYS.accessToken);
    window.localStorage.removeItem(STORAGE_KEYS.refreshToken);
    window.localStorage.removeItem(STORAGE_KEYS.currentUser);
    window.dispatchEvent(new Event(APP_EVENTS.sessionChanged));
  };

  if (!token || !user) {
    return (
      <Link className="button-secondary" href="/login">
        Login
      </Link>
    );
  }

  return (
    <div className="platform-session">
      <div className="platform-session-copy">
        <div className="platform-session-name">
          {user.full_name || user.username}
        </div>
        <div className="platform-session-meta">Connected to backend chat APIs.</div>
      </div>
      <button
        className="button-secondary platform-session-button"
        type="button"
        onClick={handleDisconnect}
      >
        Disconnect
      </button>
    </div>
  );
}
